class Solution {
    public int racecar(int target) {
        int n = target;
        int[] dp = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            dp[i] = i;
        }
        for (int i = 1; i <= n; i++) {
            int speed = 1;
            int pos = 0;
            for (int t = 0; t <= i; t++) {
                if (pos >= i) {
                    break;
                }
                if (pos + speed >= i) {
                    dp[i] = Math.min(dp[i], dp[pos] + t + 1 + (i - pos - speed) / speed);
                }
                if (speed > 0) {
                    speed = -1;
                } else {
                    speed = 1;
                }
                pos += speed;
            }
        }
        return dp[target];
    }
}
